import { describe, expect, it } from "vitest";

import { bounds, config } from "../config/index.js";
import {
  type DirectorProvider,
  type GenerateManifestOptions,
  type JudgeOptions,
  type JudgeResult,
  type ProviderFailureCode,
  type ProviderResult
} from "../director/provider/index.js";
import type { FloorContent } from "../engine/run/index.js";
import {
  MemoryArtifactFs,
  loadGenerationChain
} from "../harness/artifacts/index.js";
import { validShallowsManifestFixture } from "../schemas/fixtures/manifest.js";
import type { FloorManifest } from "../schemas/manifest.js";
import {
  defaultGate2Config,
  type Gate2Config,
  type Gate2RunOptions
} from "./gate2/run.js";
import { generateFloor } from "./repair.js";

const ROOT_DIR = "runs";
const DEPTH = validShallowsManifestFixture.depth;
const SEED = "repair-seed";
const CREATED_AT = "2026-06-12T00:00:00.000Z";
const RECORDED_AT = "2026-06-12T00:00:01.000Z";
const MODEL_ID = "mock-repair-provider";
const ORIGINAL_PROMPT = "Generate floor 3 for repair test.";
const USAGE = { latencyMs: 5, tokens: null };

describe("repair loop and fallback degradation", () => {
  it("serves a generated floor and writes a one-shot attempt chain on the happy path", async () => {
    const fs = new MemoryArtifactFs();
    const provider = new SequenceDirectorProvider([
      providerSuccess(validShallowsManifestFixture)
    ]);
    const result = await generateFloor(
      ctx("repair-happy", fs, provider, {
        gate2: passingGate2(validShallowsManifestFixture)
      })
    );
    const loaded = assertPersisted(fs, "repair-happy", result.record);

    expect(provider.prompts).toEqual([ORIGINAL_PROMPT]);
    expect(provider.options[0]?.timeoutMs).toBe(
      config.director.manifestTimeoutMs
    );
    expect(
      "manifest" in result.floor ? result.floor.manifest.depth : null
    ).toBe(DEPTH);
    expect(loaded.outcome.kind).toBe("manifest");
    expect(loaded.attempts).toHaveLength(1);
    expect(loaded.attempts[0]?.provider.ok).toBe(true);
    expect(loaded.attempts[0]?.provider.manifestPath).toBe(
      "floors/3/attempts/0/manifest.json"
    );
    expect(loaded.attempts[0]?.gateReports?.gate0?.pass).toBe(true);
    expect(loaded.attempts[0]?.gateReports?.gate1?.pass).toBe(true);
    expect(loaded.attempts[0]?.gateReports?.gate2?.pass).toBe(true);
  });

  it("serves a generated floor when only advisory HP retention fails", async () => {
    const fs = new MemoryArtifactFs();
    const provider = new SequenceDirectorProvider([
      providerSuccess(validShallowsManifestFixture)
    ]);
    const result = await generateFloor(
      ctx("repair-advisory-hp", fs, provider, {
        gate2: hpRetentionFailingGate2(validShallowsManifestFixture, "advisory")
      })
    );
    const loaded = assertPersisted(fs, "repair-advisory-hp", result.record);
    const hpCheck = loaded.attempts[0]?.gateReports?.gate2?.checks.find(
      (check) => check.code === "G2_HP_RETENTION"
    );

    expect(loaded.outcome.kind).toBe("manifest");
    expect(loaded.attempts).toHaveLength(1);
    expect(loaded.attempts[0]?.gateReports?.gate2?.pass).toBe(true);
    expect(hpCheck).toMatchObject({
      pass: false,
      advisory: true
    });
  });

  it("falls back when blocking HP retention rejects and repair cap is exhausted", async () => {
    const fs = new MemoryArtifactFs();
    const provider = new SequenceDirectorProvider([
      providerSuccess(validShallowsManifestFixture)
    ]);
    const result = await generateFloor(
      ctx("repair-blocking-hp", fs, provider, {
        gate2: hpRetentionFailingGate2(
          validShallowsManifestFixture,
          "blocking"
        ),
        repairCap: 0
      })
    );
    const loaded = assertPersisted(fs, "repair-blocking-hp", result.record);

    expect(loaded.outcome.kind).toBe("fallback");
    expect(loaded.attempts).toHaveLength(1);
    expect(loaded.attempts[0]?.gateReports?.gate2?.pass).toBe(false);
    expect(loaded.attempts[0]?.gateReports?.gate2?.verdict.codes).toContain(
      "G2_HP_RETENTION"
    );
  });

  it("repairs malformed output on the second attempt and snapshots the repair prompt", async () => {
    const fs = new MemoryArtifactFs();
    const provider = new SequenceDirectorProvider([
      providerFailure("parse_fail", "not a manifest at all"),
      providerSuccess(validShallowsManifestFixture)
    ]);
    const result = await generateFloor(
      ctx("repair-malformed", fs, provider, {
        gate2: passingGate2(validShallowsManifestFixture)
      })
    );
    const loaded = assertPersisted(fs, "repair-malformed", result.record);

    expect(provider.prompts).toHaveLength(2);
    expect(provider.prompts[1]).toMatchInlineSnapshot(`
      "Generate floor 3 for repair test.

      Your previous output failed these checks:
      - Gate 0 G0_NO_JSON: $: no JSON object found

      Fix only these checks; preserve valid content when possible.

      Offending JSON fragment(s):
      \`\`\`json
      not a manifest at all
      \`\`\`

      Return the corrected complete JSON manifest only."
    `);
    expect(loaded.outcome.kind).toBe("manifest");
    expect(loaded.attempts).toHaveLength(2);
    expect(loaded.attempts[0]?.gateReports?.gate0?.checks[0]?.code).toBe(
      "G0_NO_JSON"
    );
    expect(loaded.attempts[1]?.gateReports?.gate2?.pass).toBe(true);
  });

  it("falls back after exactly two repairs when every manifest is unrepairable", async () => {
    const fs = new MemoryArtifactFs();
    const provider = new SequenceDirectorProvider(
      [],
      providerFailure("parse_fail", "{broken")
    );
    const result = await generateFloor(
      ctx("repair-unrepairable", fs, provider)
    );
    const loaded = assertPersisted(fs, "repair-unrepairable", result.record);

    expect(provider.prompts).toHaveLength(bounds.gauntlet.repairRetriesMax + 1);
    expect(loaded.outcome).toEqual({
      kind: "fallback",
      fallbackId: "fallback:old-stock:shallows-3"
    });
    expect(loaded.attempts).toHaveLength(3);
    expect(
      loaded.attempts.every(
        (attempt) =>
          attempt.gateReports?.gate0?.checks[0]?.code === "G0_NO_JSON"
      )
    ).toBe(true);
    expect((result.floor as FloorContent).params.seed).toBe(SEED);
  });

  it("degrades immediately to fallback on provider timeout", async () => {
    const fs = new MemoryArtifactFs();
    const provider = new SequenceDirectorProvider([
      providerFailure("timeout", undefined)
    ]);
    const result = await generateFloor(ctx("repair-timeout", fs, provider));
    const loaded = assertPersisted(fs, "repair-timeout", result.record);

    expect(provider.prompts).toEqual([ORIGINAL_PROMPT]);
    expect(loaded.outcome).toEqual({
      kind: "fallback",
      fallbackId: "fallback:old-stock:shallows-3"
    });
    expect(loaded.attempts).toHaveLength(1);
    expect(loaded.attempts[0]?.provider.ok).toBe(false);
    expect(loaded.attempts[0]?.provider.error?.code).toBe("timeout");
    expect(loaded.attempts[0]?.gateReports).toBeUndefined();
    expect((result.floor as FloorContent).params.seed).toBe(SEED);
  });

  it("never exceeds the repair cap under an adversarial always-fail provider", async () => {
    const fs = new MemoryArtifactFs();
    const provider = new SequenceDirectorProvider(
      [],
      providerFailure(
        "validate_fail",
        JSON.stringify({ protocolVersion: "bad" })
      )
    );
    const result = await generateFloor(ctx("repair-cap", fs, provider));
    const loaded = assertPersisted(fs, "repair-cap", result.record);

    expect(provider.prompts).toHaveLength(3);
    expect(provider.prompts.slice(1)).toHaveLength(
      bounds.gauntlet.repairRetriesMax
    );
    expect(loaded.attempts).toHaveLength(3);
    expect(loaded.outcome.kind).toBe("fallback");
    expect(
      result.record.attempts.map((attempt) => attempt.attemptIndex)
    ).toEqual([0, 1, 2]);
  });
});

class SequenceDirectorProvider implements DirectorProvider {
  readonly prompts: string[] = [];
  readonly options: GenerateManifestOptions[] = [];
  private readonly results: ProviderResult[];
  private readonly defaultResult: ProviderResult;

  constructor(
    results: readonly ProviderResult[],
    defaultResult: ProviderResult = providerFailure("process_error", undefined)
  ) {
    this.results = [...results];
    this.defaultResult = defaultResult;
  }

  async generateManifest(
    prompt: string,
    options: GenerateManifestOptions = {}
  ): Promise<ProviderResult> {
    this.prompts.push(prompt);
    this.options.push(options);

    return this.results.shift() ?? this.defaultResult;
  }

  async judge(
    prompt: string,
    options: JudgeOptions = {}
  ): Promise<JudgeResult> {
    void prompt;
    void options;

    return {
      ok: false,
      error: {
        code: "process_error",
        message: "judge unused in repair tests"
      },
      usage: USAGE
    };
  }

    kind: "manifest",
    floor: gate2Evaluation.floor,
    gateReports
  };
};

const evaluateGate2 = (
  manifest: FloorManifest,
  options: Gate2RunOptions = {}
): Gate2EvaluationResult => {
  let floor: MaterializedFloor;

  try {
    floor = materialize(manifest, manifest.params.seed, {
      ...(options.transformFloor === undefined
        ? {}
        : { transformFloor: options.transformFloor })
    }).floor;
  } catch (error) {
    return {
      kind: "fail",
      report: materializationFailureReport(manifest, options, error)
    };
  }

  try {
    const report = runGate2(manifest, options);

    if (!report.pass) {
      return {
        kind: "fail",
        report
      };
    }

    return {
      kind: "pass",
      floor,
      report
    };
  } catch (error) {
    return {
      kind: "fail",
      report: materializationFailureReport(manifest, options, error)
    };
  }
};

const materializationFailureReport = (
  manifest: FloorManifest,
  options: Gate2RunOptions,
  source: unknown
): Gate2Report => {
  const gateConfig = options.config ?? defaultGate2Config(manifest);
  const detail =
    source instanceof Error
      ? `candidate floor could not be materialized: ${source.message}`
      : `candidate floor could not be materialized: ${String(source)}`;
  const check: Gate2Check = {
    code: "G2_MATERIALIZATION",
    pass: false,
    detail
  };

  return {
    gate: 2,
    pass: false,
    verdict: {
      status: "reject",
      codes: ["G2_MATERIALIZATION"]
    },
    checks: [check],
    metrics: {
      totalRuns: 0,
      clearCount: 0,
      reachedStairsCount: 0,
      questCompletedCount: 0,
      deathCount: 0,
      clearRatePercent: 0,
      medianHpRetentionPercent: 0,
      minTurns: 0,
      maxTurns: 0
    },
    candidate: {
      seed: manifest.params.seed,
      stairsReachable: false,
      pathLength: null,
      hasThreatOnPath: false,
      placementDeviationCount: 0
    },
    ensemble: {
      policies: gateConfig.policies,
      seeds: gateConfig.seeds,
      maxTurns: gateConfig.maxTurns
    },
    elapsedMs: 0,
    wallClockBudgetMs: gateConfig.wallClockBudgetMs
  };
};

const collectFailedChecks = (
  gateReports: NonNullable<GenerationAttemptInput["gateReports"]>
): readonly {
  readonly gate: 0 | 1 | 2;
  readonly code: GateCheck["code"] | Gate2Check["code"];
  readonly detail: string;
}[] => [
  ...(gateReports.gate0 === undefined
    ? []
    : failedChecks(gateReports.gate0).map(withGate(gateReports.gate0))),
  ...(gateReports.gate1 === undefined
    ? []
    : failedChecks(gateReports.gate1).map(withGate(gateReports.gate1))),
  ...(gateReports.gate2 === undefined
    ? []
    : gateReports.gate2.checks
        .filter((check) => !check.pass)
        .map((check) => ({
          gate: 2 as const,
          code: check.code,
          detail: check.detail
        })))
];

const withGate =
  (report: GateReport) =>
  (
    check: GateCheck
  ): {
    readonly gate: 0 | 1;
    readonly code: GateCheck["code"];
    readonly detail: string;
  } => ({
    gate: report.gate,
    code: check.code,
    detail: check.detail
  });

const offendingFragments = (
  providerResult: ProviderResult,
  manifest: FloorManifest | undefined
): readonly string[] => {
  const raw = providerResult.ok ? providerResult.raw : providerResult.raw;
  if (raw !== undefined && raw.trim().length > 0) {
    return [truncateFragment(raw)];
  }

  if (manifest !== undefined) {
    return [truncateFragment(JSON.stringify(manifest, null, 2))];
  }

  return [];
};

const truncateFragment = (fragment: string): string =>
  fragment.length <= FRAGMENT_MAX_CHARS
    ? fragment
    : `${fragment.slice(0, FRAGMENT_MAX_CHARS)}\n...<truncated>`;

const serveFallback = (
  ctx: GenerateFloorContext,
  attempts: readonly GenerationAttemptInput[]
): GenerateFloorResult => {
  const fallbackProvider =
    ctx.fallbackProvider ?? createFallbackFloorContentProvider();
  const floor = fallbackProvider.getFloor(ctx.depth, ctx.seed);
  const record = writeRecord(ctx, attempts, {
    kind: "fallback",
    fallbackId: fallbackId(ctx.depth, floor)
  });

  return { floor, record };
};

const fallbackId = (depth: number, floor: FloorContent): string =>
  `fallback:old-stock:${floor.params.bandOrSize}-${depth}`;

const writeRecord = (
  ctx: GenerateFloorContext,
  attempts: readonly GenerationAttemptInput[],
  outcome: Parameters<typeof writeGenerationRecord>[0]["outcome"]
): GenerationRecord => {
  const createdAt = ctx.createdAt ?? ctx.now?.() ?? new Date().toISOString();
  const recordedAt = ctx.recordedAt ?? ctx.now?.() ?? createdAt;

  return writeGenerationRecord(
    {
      runId: ctx.runId,
      depth: ctx.depth,
      seed: ctx.seed,
      modelId: ctx.modelId,
      createdAt,
      recordedAt,
      attempts,
      outcome
    },
    ctx.artifacts
  );
};

const servedManifestPath = (
  ctx: GenerateFloorContext,
  attemptIndex: number
): string => {
  const rootDir = trimTrailingSlash(ctx.artifacts?.rootDir ?? DEFAULT_ROOT_DIR);
  return `${rootDir}/${ctx.runId}/floors/${ctx.depth}/attempts/${attemptIndex}/manifest.json`;
};

const trimTrailingSlash = (value: string): string => value.replace(/\/+$/g, "");

  }
}

const ctx = (
  runId: string,
  fs: MemoryArtifactFs,
  provider: DirectorProvider,
  options: {
    readonly gate2?: Gate2RunOptions;
    readonly repairCap?: number;
  } = {}
) => ({
  prompt: ORIGINAL_PROMPT,
  provider,
  runId,
  depth: DEPTH,
  seed: SEED,
  modelId: MODEL_ID,
  createdAt: CREATED_AT,
  recordedAt: RECORDED_AT,
  artifacts: { fs, rootDir: ROOT_DIR },
  ...options
});

const providerSuccess = (manifest: FloorManifest): ProviderResult => ({
  ok: true,
  raw: JSON.stringify(manifest),
  manifest,
  usage: USAGE
});

const providerFailure = (
  code: ProviderFailureCode,
  raw: string | undefined
): ProviderResult => ({
  ok: false,
  ...(raw === undefined ? {} : { raw }),
  error: {
    code,
    message: `mock ${code}`
  },
  usage: USAGE
});

const passingGate2 = (manifest: FloorManifest): Gate2RunOptions => ({
  config: currentBotRealityConfig(manifest)
});

const hpRetentionFailingGate2 = (
  manifest: FloorManifest,
  hpRetentionMode: Gate2Config["hpRetentionMode"]
): Gate2RunOptions => {
  const base = currentBotRealityConfig(manifest);

  return {
    config: {
      ...base,
      hpRetentionMode,
      thresholdsByBand: {
        ...base.thresholdsByBand,
        shallows: {
          ...base.thresholdsByBand.shallows,
          medianHpRetentionPercent: {
            min: 0,
            max: 50
          }
        }
      }
    }
  };
};

const currentBotRealityConfig = (manifest: FloorManifest): Gate2Config => {
  const base = defaultGate2Config(manifest);

  return {
    ...base,
    policies: ["balanced", "aggressive"],
    seeds: ["repair-gate2-a", "repair-gate2-b"],
    maxTurns: 120,
    wallClockBudgetMs: 1_000,
    thresholdsByBand: {
      shallows: allowCurrentHpRetention(base.thresholdsByBand.shallows),
      middle: allowCurrentHpRetention(base.thresholdsByBand.middle),
      lowest: allowCurrentHpRetention(base.thresholdsByBand.lowest)
    }
  };
};

const allowCurrentHpRetention = (
  threshold: Gate2Config["thresholdsByBand"]["shallows"]
): Gate2Config["thresholdsByBand"]["shallows"] => ({
  ...threshold,
  medianHpRetentionPercent: {
    ...threshold.medianHpRetentionPercent,
    max: 100
  }
});

const assertPersisted = (
  fs: MemoryArtifactFs,
  runId: string,
  record: Awaited<ReturnType<typeof generateFloor>>["record"]
) => {
  const loaded = loadGenerationChain(runId, DEPTH, { fs, rootDir: ROOT_DIR });

  expect(loaded).toEqual(record);
  expect(loaded.attempts.map((attempt) => attempt.attemptIndex)).toEqual(
    loaded.attempts.map((_, index) => index)
  );
  expect(
    loaded.attempts.every((attempt) => attempt.rawOutputPath.length > 0)
  ).toBe(true);

  return loaded;
};

