  type EntityIdCounters,
  type EntityKind,
  type GameState,
  type Position,
} from "./types.js";

export const ROOT_RNG_STREAM_ID = "root" as const;

export const createInitialEntityCounters = (): EntityIdCounters => ({
  enemy: 0,
  npc: 0,
  item: 0,
  trap: 0,
});

export interface EntityIdAllocation {
  readonly id: EntityId;
  readonly entityCounters: EntityIdCounters;
}

export const allocateEntityId = (
  counters: EntityIdCounters,
  kind: EntityKind,
): EntityIdAllocation => {
  const next = counters[kind] + 1;

  return {
    id: `${kind}#${next}` as EntityId,
    entityCounters: {
      ...counters,
      [kind]: next,
    },
  };
};

export const depthBandForDepth = (
  depth: number,
  gameConfig: GameConfig = defaultConfig,
): DepthBand => {
  if (!Number.isSafeInteger(depth)) {
    throw new RangeError("depth must be a safe integer");
  }

  for (const [band, range] of depthBandEntries(gameConfig)) {
    if (depth >= range.minFloor && depth <= range.maxFloor) {
      return band;
    }
  }

  throw new RangeError(`depth ${depth} is outside configured depth bands`);
};

export const createInitialState = (
  seed: string,
  gameConfig: GameConfig = defaultConfig,
): GameState => {
  const turn = createClock().now();
  const depth = initialDepth(gameConfig);
  const band = depthBandForDepth(depth, gameConfig);
  const runId = runIdForSeed(seed);
  const startPosition = unplacedPosition();
  const playerHp = gameConfig.playerCharacter.stats.hp.start;
  const playerFullness = gameConfig.playerCharacter.stats.fullness.start;

  return {
    version: {
      protocolVersion: PROTOCOL_VERSION,
      engineVersion: ENGINE_VERSION,
    },
    run: {
      runId,
      seed,
      depth,
      band,
      turn,
      terminalStatus: ACTIVE_TERMINAL_STATUS,
      itemKnowledge: {
        identifiedDefinitionIds: [],
        bonusRevealedItemInstanceIds: [],
        chargesByItemInstanceId: {},
      },
    },
    floor: {
      floorId: `floor#${depth}`,
      depth,
      band,
      geometry: {
        refId: `floor-geometry#${depth}`,
        opaque: null,
      },
    },
    player: {
      hp: {
        current: playerHp,
        max: playerHp,
      },
      level: gameConfig.playerCharacter.stats.level.start,
      xp: 0,
      fullness: {
        current: playerFullness,
        max: bounds.playerCharacter.fullnessCap,
      },
      position: startPosition,
      inventory: Array.from(
        { length: gameConfig.playerCharacter.inventory.slots },
        () => null,
      ),
      equipment: {
        weapon: null,
        armor: null,
        charms: Array.from(
          { length: gameConfig.playerCharacter.equipmentSlots.charms },
          () => null,
        ),
      },
      statuses: [],
    },
    entities: {},
    quests: {
      quests: {},
      activeQuestIds: [],
      completedQuestIds: [],
      failedQuestIds: [],
    },
    log: [
      {
        turn,
        type: "state_created",
        data: {
          runId,
          seed,
          depth,
          band,
        },
      },
    ],
    rng: {
      rootSeed: seed,
      streams: {
        [ROOT_RNG_STREAM_ID]: {
          streamId: ROOT_RNG_STREAM_ID,
          seed,
          parentStreamId: null,
          draws: 0,
        },
      },
    },
    ids: {
      entityCounters: createInitialEntityCounters(),
    },
  };
};

const runIdForSeed = (seed: string): string => `run#${seed}`;

const unplacedPosition = (): Position => ({
  x: 0,
  y: 0,
});

const initialDepth = (gameConfig: GameConfig): number => {
  const entries = depthBandEntries(gameConfig);
  const firstEntry = entries[0];

  if (firstEntry === undefined) {
    throw new RangeError("config must define at least one depth band");
  }

  let depth = firstEntry[1].minFloor;
  for (const [, range] of entries) {
    if (range.minFloor < depth) {
      depth = range.minFloor;
    }
  }

  return depth;
};

const depthBandEntries = (
  gameConfig: GameConfig,
): readonly [
  DepthBand,
  {
    readonly minFloor: number;
    readonly maxFloor: number;
  },
][] =>
  Object.entries(gameConfig.runStructure.depthBands) as readonly [
    DepthBand,
    {
      readonly minFloor: number;
      readonly maxFloor: number;
    },
  ][];

import type {
  EntityId,
  EntityInstance,
  GameState,
  InventorySlot,
  Position,
  SerializableRecord,
} from "../state/index.js";
import {
  chebyshevDistance,
  getTile,
  inBounds,
  isWalkableTile,
  Terrain,
  type TileGrid,
} from "../map/index.js";

export const MOVE_DIRECTIONS = [
  { direction: "northwest", offset: { x: -1, y: -1 } },
  { direction: "north", offset: { x: 0, y: -1 } },
  { direction: "northeast", offset: { x: 1, y: -1 } },
  { direction: "west", offset: { x: -1, y: 0 } },
  { direction: "east", offset: { x: 1, y: 0 } },
  { direction: "southwest", offset: { x: -1, y: 1 } },
  { direction: "south", offset: { x: 0, y: 1 } },
  { direction: "southeast", offset: { x: 1, y: 1 } },
] as const;

export type MoveDirection = (typeof MOVE_DIRECTIONS)[number]["direction"];

export type ActionTarget =
  | {
      readonly kind: "self";
    }
  | {
      readonly kind: "entity";
      readonly entityId: EntityId;
    }
  | {
      readonly kind: "cell";
      readonly cell: Position;
    };

export type MoveAction = {
  readonly kind: "move";
  readonly direction: MoveDirection;
};

export type AttackAction = {
  readonly kind: "attack";
  readonly targetId: EntityId;
};

export type UseItemAction = {
  readonly kind: "use_item";
  readonly itemId: string;
  readonly target?: ActionTarget;
  readonly direction?: MoveDirection;
};

export type PickupAction = {
  readonly kind: "pickup";
};

export type TalkAction = {
  readonly kind: "talk";
  readonly npcId: EntityId;
};

export type WaitAction = {
  readonly kind: "wait";
};

export type DescendAction = {
  readonly kind: "descend";
};

export type InspectAction = {
  readonly kind: "inspect";
  readonly cell: Position;
};

export type AbortAction = {
  readonly kind: "abort";
};

export type PlayerAction =
  | MoveAction
  | AttackAction
  | UseItemAction
  | PickupAction
  | TalkAction
  | WaitAction
  | DescendAction
  | InspectAction
  | AbortAction;

export type LegalActionResult = {
  readonly status: "legal";
};

export type IllegalActionResult = {
  readonly status: "illegal";
  readonly reason: string;
};

export type ActionLegality = LegalActionResult | IllegalActionResult;

export const LEGAL_ACTION = { status: "legal" } as const satisfies ActionLegality;

export const isActionLegal = (
  result: ActionLegality,
): result is LegalActionResult => result.status === "legal";

export const checkActionLegality = (
  state: GameState,
  action: PlayerAction,
): ActionLegality => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return illegal(`run is terminal (${state.run.terminalStatus})`);
  }

  switch (action.kind) {
    case "move":
      return checkMoveAction(state, action);
    case "attack":
      return checkAttackAction(state, action);
    case "use_item":
      return checkUseItemAction(state, action);
    case "pickup":
      return checkPickupAction(state);
    case "talk":
      return checkTalkAction(state, action);
    case "wait":
      return LEGAL_ACTION;
    case "descend":
      return checkDescendAction(state);
    case "inspect":
      return checkInspectAction(state, action);
    case "abort":
      return LEGAL_ACTION;
  }
};

export const getAvailableActions = (state: GameState): readonly PlayerAction[] => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return [];
  }

  const actions: PlayerAction[] = [];

  for (const { direction } of MOVE_DIRECTIONS) {
    const action = { kind: "move", direction } as const;
    pushIfLegal(actions, state, action);
  }

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "enemy") {
      pushIfLegal(actions, state, {
        kind: "attack",
        targetId: entity.id,
      });
    }
  }

  for (const item of carriedItems(state.player.inventory)) {
    pushIfLegal(actions, state, {
      kind: "use_item",
      itemId: item.itemInstanceId,
    });
  }

  pushIfLegal(actions, state, { kind: "pickup" });

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "npc") {
      pushIfLegal(actions, state, {
        kind: "talk",
        npcId: entity.id,
      });
    }
  }

  pushIfLegal(actions, state, { kind: "wait" });
  pushIfLegal(actions, state, { kind: "descend" });
  actions.push(...availableInspectActions(state));
  pushIfLegal(actions, state, { kind: "abort" });

  return actions;
};

export const destinationForMove = (
  origin: Position,
  direction: MoveDirection,
): Position => {
  const offset = offsetForDirection(direction);

  return {
    x: origin.x + offset.x,
    y: origin.y + offset.y,
  };
};

export const gridFromState = (state: GameState): TileGrid | null => {
  const opaque = state.floor.geometry.opaque;

  if (!isTileGridRecord(opaque)) {
    return null;
  }

  return opaque as unknown as TileGrid;
};

const checkMoveAction = (
  state: GameState,
  action: MoveAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  const destination = destinationForMove(state.player.position, action.direction);

  if (!inBounds(grid, destination)) {
    return illegal(
      `move ${action.direction} leaves the map at (${destination.x}, ${destination.y})`,
    );
  }

  const tile = getTile(grid, destination);

  if (!isWalkableTile(tile)) {
    return illegal(`terrain ${tile.terrain} blocks movement`);
  }

  return LEGAL_ACTION;
};

const checkAttackAction = (
  state: GameState,
  action: AttackAction,
): ActionLegality => {
  const target = state.entities[action.targetId];

  if (target === undefined) {
    return illegal(`attack target ${action.targetId} does not exist`);
  }

  if (target.kind !== "enemy") {
    return illegal(`attack target ${action.targetId} is not an enemy`);
  }

  if (!isAdjacentToPlayer(state, target.position)) {
    return illegal(`attack target ${action.targetId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

