/** Frozen contract surface for the repair loop (phase 36). */
export const GATE_REASON_CODES = [
  "G0_NO_JSON",
  "G0_INVALID_JSON",
  "G0_SCHEMA",
  "G1_PROTOCOL_VERSION",
  "G1_REF_INTEGRITY",
  "G1_CALLBACK_REF",
  "G1_PLACEMENT_HINT",
  "G1_ROSTER_BUDGET",
  "G1_ENEMY_STATS",
  "G1_ITEM_VALUE",
  "G1_TRAP_LETHALITY",
  "G1_ENTITY_CAP",
  "G1_TEXT_CAP",
  "G1_SIGNATURE",
] as const;

export type GateReasonCode = (typeof GATE_REASON_CODES)[number];

export type GateCheck = {
  readonly code: GateReasonCode;
  readonly pass: boolean;
  readonly detail: string;
};

export type GateReport = {
  readonly gate: 0 | 1;
  readonly pass: boolean;
  readonly checks: readonly GateCheck[];
};

export const passCheck = (
  code: GateReasonCode,
  detail: string,
): GateCheck => ({
  code,
  pass: true,
  detail,
});

export const failCheck = (
  code: GateReasonCode,
  detail: string,
): GateCheck => ({
  code,
  pass: false,
  detail,
});

export const buildGateReport = (
  gate: 0 | 1,
  checks: readonly GateCheck[],
): GateReport => ({
  gate,
  pass: checks.every((check) => check.pass),
  checks,
});

export const failedChecks = (report: GateReport): readonly GateCheck[] =>
  report.checks.filter((check) => !check.pass);

export const formatGateReport = (report: GateReport): string => {
  const header = `Gate ${report.gate}: ${report.pass ? "PASS" : "FAIL"}`;
  const lines = report.checks.map(
    (check) =>
      `  [${check.pass ? "ok" : "FAIL"}] ${check.code}: ${check.detail}`,
  );

  return [header, ...lines].join("\n");
};

import {
  parseManifest,
  type ManifestParseError,
} from "../../schemas/manifest.js";
import {
  buildGateReport,
  failCheck,
  passCheck,
  type GateCheck,
  type GateReport,
} from "./report.js";

export const runGate0 = (raw: string): GateReport => {
  const result = parseManifest(raw);

  if (result.ok) {
    return buildGateReport(0, [
      passCheck("G0_SCHEMA", "manifest schema valid"),
    ]);
  }

  return buildGateReport(0, mapParseErrorsToChecks(result.errors));
};

const mapParseErrorsToChecks = (
  errors: readonly ManifestParseError[],
): GateCheck[] => {
  const codes = new Set(errors.map(classifyParseError));

  if (codes.size === 1) {
    const code = [...codes][0]!;
    return [failCheck(code, summarizeParseErrors(errors))];
  }

  return [...codes].map((code) =>
    failCheck(
      code,
      summarizeParseErrors(errors.filter((error) => classifyParseError(error) === code)),
    ),
  );
};

const classifyParseError = (
  error: ManifestParseError,
): "G0_NO_JSON" | "G0_INVALID_JSON" | "G0_SCHEMA" => {
  const message = error.message.toLowerCase();

  if (
    message === "no json object found" ||
    message === "unterminated json object"
  ) {
    return "G0_NO_JSON";
  }

  if (message.startsWith("invalid json")) {
    return "G0_INVALID_JSON";
  }

  return "G0_SCHEMA";
};

const summarizeParseErrors = (
  errors: readonly ManifestParseError[],
): string =>
  errors.map((error) => `${error.path}: ${error.message}`).join("; ");

  depth: input.depth,
  attempts: input.attempts,
  outcome: input.outcome,
});

const attempt = (input: {
  readonly depth: number;
  readonly attemptIndex: number;
  readonly ok: boolean;
  readonly latencyMs: number;
  readonly tokens: ProviderTokenUsage | null;
  readonly gate0?: boolean;
  readonly gate1?: boolean;
  readonly gate2?: Gate2Report;
}): GenerationAttemptRecord => ({
  attemptIndex: input.attemptIndex,
  promptHash: `prompt-${input.depth}-${input.attemptIndex}`,
  rawOutputPath: `floors/${input.depth}/attempts/${input.attemptIndex}/raw.txt`,
