const fs=require('fs');
for (const file of ['items','enemies','traps','npcs','quests']) {
  const arr=JSON.parse(fs.readFileSync("'`content/fallback/${file}.json`,'"'utf8'));
  let max=0, maxstr='';
  const strings=[];
  const walk=(v,path='')=>{ if(typeof v==='string' && /name|text|label|title/.test(path)) strings.push([path,v]); else if(Array.isArray(v)) v.forEach((x,i)=>walk(x,"'`${path}.${i}`)); else if(v&&typeof v==='"'object') for(const [k,val] of Object.entries(v)) walk(val,path?"'`${path}.${k}`:k); };
  walk(arr,file);
  for(const [p,s] of strings){ if(s.length>max){max=s.length; maxstr=`${p}: ${s}`;} }
  console.log(file, strings.length, max, maxstr);
}
NODE'

